const all = $input.all().map(i => i.json);

const RISK_THRESHOLD   = 6;
const RESPONSE_HRS_MAX = 48;
const NEG_SIGNALS_MAX  = 3;

const alertWorthy = all.filter(c =>
  c.risk_score_heuristic        >= RISK_THRESHOLD   ||
  c.avg_team_response_hours_30d >  RESPONSE_HRS_MAX ||
  c.negative_signals_30d        >= NEG_SIGNALS_MAX   ||
  c.overdue_actions             >  0
);

const critical = alertWorthy.filter(c => c.risk_score_heuristic >= 8);
const warning  = alertWorthy.filter(c => c.risk_score_heuristic >= 6 && c.risk_score_heuristic < 8);
const watch    = alertWorthy.filter(c => c.risk_score_heuristic < 6);

if (alertWorthy.length === 0) {
  return [{ json: { has_alerts: false, alertWorthy: [], critical: [], warning: [], watch: [], total: all.length } }];
}

return [{ json: { has_alerts: true, alertWorthy, critical, warning, watch, total: all.length } }];

const { critical, warning, watch, total, alertWorthy } = $input.item.json;

const today = new Date().toLocaleDateString('es-ES', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'Europe/Madrid'
});

const fmt = (c) => {
  const risk = Number(c.risk_score_heuristic).toFixed(1);
  const resp = c.avg_team_response_hours_30d > 0
    ? `${Number(c.avg_team_response_hours_30d).toFixed(0)}h`
    : '—';
  const neg  = c.negative_signals_30d;
  const od   = c.overdue_actions;
  const stalled = c.stalled_threads_gt_72h;

  const badges = [];
  if (neg >= 3)                              badges.push('⚠️ señales negativas');
  if (c.avg_team_response_hours_30d > 48)    badges.push('🐢 respuesta lenta');
  if (od > 0)                                badges.push(`📋 ${od} acción${od>1?'es':''} vencida${od>1?'s':''}`);
  if (stalled > 0)                           badges.push(`🔇 ${stalled} hilo${stalled>1?'s':''} estancado${stalled>1?'s':''}`);
  const badgeStr = badges.length ? `  ${badges.join(' · ')}` : '';

  return `• *${c.client_name}*  Risk: *${risk}* | Respuesta: ${resp} | Neg: ${neg} | Vencidas: ${od}${badgeStr}`;
};

const sections = [];
if (critical.length) sections.push(`🔴 *CRÍTICO* (risk ≥ 8)\n${critical.map(fmt).join('\n')}`);
if (warning.length)  sections.push(`🟡 *ATENCIÓN* (risk 6–7.9)\n${warning.map(fmt).join('\n')}`);
if (watch.length)    sections.push(`🟠 *VIGILAR*\n${watch.map(fmt).join('\n')}`);

const slackText = [
  `*📊 DecadaHUB — Resumen diario de cartera*`,
  `${today}  ·  ${alertWorthy.length} clientes necesitan atención de ${total} totales`,
  '',
  ...sections,
  '',
  `_Generado automáticamente por DecadaHUB · Flujo 06_`
].join('\n');

return [{ json: { slack_text: slackText, alertCount: alertWorthy.length, total } }];
